ROUTE_B64 = ''

#!/usr/bin/env python3
from datetime import datetime
from pathlib import Path
import base64
import shutil
import sys

ROOT = Path.cwd()
ROUTE = ROOT / "src/app/api/sectors/route.ts"

if not ROUTE.exists():
    print("خطأ: شغّل الملف من داخل مجلد apps/web")
    sys.exit(1)

stamp = datetime.now().strftime("%Y%m%d-%H%M%S")
backup = Path("/tmp") / ("sector-rate-limit-backup-" + stamp + ".ts")
shutil.copy2(ROUTE, backup)

ROUTE.write_bytes(base64.b64decode(ROUTE_B64))

print("تم تطبيق إصلاح حد طلبات القطاعات.")
print("- يجرب Massive Grouped بثلاثة طلبات فقط")
print("- ينتقل تلقائيًا إلى Finnhub عند عدم توفر Grouped")
print("- لا يطلب كل شركة من Massive بشكل منفصل")
print("- كاش مشترك لمدة خمس دقائق")
print("- صفحة القطاع تستفيد من كاش الخريطة بدل إعادة 12 قطاعًا")
print("النسخة الاحتياطية: " + str(backup))
print("الخطوة التالية: npm run build")
